effect.shader:
void main() {
    vec2 texelSize = 1.0 / getTexSize(inputImg.size);
    vec2 center = vec2(0.5 + centerPoint.x/500., 0.5 - centerPoint.y/500.);
    vec2 v = acScreenNorm.st - (vec4(center,0.0,1.0) * acLayerToScreen).xy;
    float speed = length(strength / 2.0 / texelSize);
    if(adaptive)
        speed *= length( acLayerNorm.st - center );
    else
        speed *= smoothstep( 0.0, length(texelSize)*5.0, length( acLayerNorm.st - center ));
    int nSamples = int(clamp(speed, 1.01, 100.01));
    vec4 originalColor = texture2DCv(inputImg.texture,acScreenNorm.st);
    vec4 outColor = originalColor;
    vec2 vnorm = normalize(v)*texelSize*speed;
    vec2 offsetScale = vec2(1., 1.);
    if( acScreenSize.y > acScreenSize.x ) {
        offsetScale.x *= acScreenSize.x / acScreenSize.y;
    } else {
        offsetScale.y *= acScreenSize.y / acScreenSize.x;
    }

    outColor.rgb = outColor.a > 0.0 ? outColor.rgb/outColor.a : outColor.rgb;
    for(int i=1; i<nSamples; i++ ) {
        vec2 offset = vnorm * (float(i) / float(nSamples - 1) - (0.5+bias/2.0));
        offset *= offsetScale;

        vec4 c = texture2DCv(inputImg.texture, acScreenNorm.st-offset);

        float r;
        float g;
        float b;
        float a;
        if( rmode == 0 ) {
            r = min(outColor.r,c.r);
        } else if( rmode == 1 ) {
            r = max(outColor.r,c.r);
        } else if( rmode == 3 ) {
            r = outColor.r + c.r;
        } else {
            r = outColor.r;
        }
        if( gmode == 0 ) {
            g = min(outColor.g,c.g);
        } else if( gmode == 1 ) {
            g = max(outColor.g,c.g);
        } else if( gmode == 3 ) {
            g = outColor.g + c.g;
        } else {
            g = outColor.g;
        }
        if( bmode == 0 ) {
            b = min(outColor.b,c.b);
        } else if( bmode == 1 ) {
            b = max(outColor.b,c.b);
        } else if( bmode == 3 ) {
            b = outColor.b + c.b;
        } else {
            b = outColor.b;
        }
        if( amode == 0 ) {
            a = min(outColor.a,c.a);
        } else if( amode == 1 ) {
            a = max(outColor.a,c.a);
        } else if( amode == 3 ) {
            a = outColor.a + c.a;
        } else {
            a = outColor.a;
        }
        outColor = vec4(r,g,b,a);
    }
    outColor = outColor / vec4(
        rmode == 3 ? float(nSamples) : 1.0,
        gmode == 3 ? float(nSamples) : 1.0,
        bmode == 3 ? float(nSamples) : 1.0,
        amode == 3 ? float(nSamples) : 1.0
    );
    outColor.rgb *= outColor.a;
    gl_FragColor = mix(originalColor,outColor,alpha);
}
